namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _all;
    private readonly Lock _lock = new();

    public NotificationService()
    {
        _all = new List<NotificationItem>
        {
            new() { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new() { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new() { Id = _nextId++, Message = "New feature: dark mode is available.", Timestamp = DateTime.UtcNow.AddMinutes(-1) },
        };
    }

    /// <summary>Returns all notifications created up to this moment.</summary>
    public Task<List<NotificationItem>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_all.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    /// <summary>Returns only notifications with Id greater than <paramref name="sinceId"/>.</summary>
    public Task<List<NotificationItem>> GetNewSinceAsync(int sinceId)
    {
        // Simulate a new notification appearing roughly every 10 seconds
        MaybeAddFake();

        lock (_lock)
        {
            return Task.FromResult(
                _all.Where(n => n.Id > sinceId)
                    .OrderByDescending(n => n.Timestamp)
                    .ToList());
        }
    }

    private void MaybeAddFake()
    {
        lock (_lock)
        {
            if (Random.Shared.NextDouble() < 0.5)
            {
                var messages = new[]
                {
                    "Someone liked your post.",
                    "You have a new follower.",
                    "Server maintenance scheduled.",
                    "Your report is ready to download.",
                    "A comment was added to your issue.",
                };

                _all.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = messages[Random.Shared.Next(messages.Length)],
                    Timestamp = DateTime.UtcNow,
                });
            }
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    [PersistentState]
    public List<NotificationItem>? PersistedNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (PersistedNotifications is not null)
        {
            // Interactive render: state was restored from prerender — skip the fetch
            notifications = PersistedNotifications;
        }
        else
        {
            // Prerender: load from service and persist for the interactive handoff
            notifications = await NotificationSvc.GetAllAsync();
            PersistedNotifications = notifications;
        }

        _lastSeenId = notifications.Count > 0
            ? notifications.Max(n => n.Id)
            : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs after the interactive runtime attaches — never during prerender
            _cts = new CancellationTokenSource();
            _ = PollForNewNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNewNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newer = await NotificationSvc.GetNewSinceAsync(_lastSeenId);
                if (newer.Count > 0)
                {
                    notifications.InsertRange(0, newer);
                    _lastSeenId = notifications.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

